package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVParser;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;
import org.mockito.Mockito;

class CSVFormatTest {

    private Reader mockReader;

    @BeforeEach
    void setUp() {
        mockReader = mock(Reader.class);
    }

    @Test
    void testParseReturnsCSVParserInstance() throws IOException {
        try (MockedConstruction<CSVParser> mocked = Mockito.mockConstruction(CSVParser.class,
                (mock, context) -> {
                    // No-op: default mock behavior
                })) {
            CSVFormat format = CSVFormat.DEFAULT;
            CSVParser parser = format.parse(mockReader);

            assertNotNull(parser);
            // Verify that CSVParser constructor was called with correct arguments
            assertEquals(1, mocked.constructed().size());
            CSVParser constructedParser = mocked.constructed().get(0);
            assertSame(parser, constructedParser);
        }
    }

    @Test
    void testParseWithNullReaderThrowsNullPointerException() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertThrows(NullPointerException.class, () -> format.parse(null));
    }
}
